    async function getEmbyServerId() { if (embyServerId) return embyServerId; try { const url = `${embyConfig.host}/emby/System/Info?api_key=${embyConfig.apiKey}`; const res = await gmRequest(url); const data = JSON.parse(res.responseText); if (data.Id) { embyServerId = data.Id; GM_setValue('embyServerId', embyServerId); return embyServerId; } } catch (e) { console.error("Failed to get Emby Server ID", e); } return null; }
