    async function handleEmbyDelete(avId, embyId, actorName, elementToRemove) { let finalId = embyId; if (!finalId) { try { const searchUrl = `${embyConfig.host}/emby/Items?api_key=${embyConfig.apiKey}&Recursive=true&IncludeItemTypes=Movie,Video&SearchTerm=${encodeURIComponent(avId)}`; const res = await gmRequest(searchUrl); const data = JSON.parse(res.responseText); if (data.Items && data.Items.length > 0) finalId = data.Items[0].Id; } catch (e) {} } if (!finalId) return alert("无法获取 Emby ID，删除失败。"); showCustomConfirm("确认删除？", async () => { try { const url = `${embyConfig.host}/emby/Items/${finalId}?api_key=${embyConfig.apiKey}`; await gmRequest(url, "DELETE"); if (elementToRemove) elementToRemove.remove(); if (libraryCollections[actorName]) { const idx = libraryCollections[actorName].indexOf(avId); if (idx !== -1) { libraryCollections[actorName].splice(idx, 1); if (libraryCollections[actorName].length === 0) delete libraryCollections[actorName]; GM_setValue('libraryCollections', libraryCollections); } } if (playbackData[avId]) { delete playbackData[avId]; GM_setValue('javdb_playback_data', playbackData); } showStatusToast("已从媒体库中删除"); const row = document.getElementById(`detail-actor-row-${actorName}`); if (row) { const box = row.querySelector('.javdb-collection-box'); if (box) { const newCount = (libraryCollections[actorName] || []).length; box.textContent = newCount > 0 ? `${newCount} 部` : '-'; } } } catch (e) { alert("删除失败: " + e.message); } }, '确认'); }
