    function showCustomConfirm(text, onConfirm, btnText = '确认') { const modal = document.createElement('div'); modal.className = 'javdb-custom-confirm'; modal.style.top = '50%'; modal.style.left = '50%'; modal.style.transform = 'translate(-50%, -50%)'; modal.innerHTML = `<div class="javdb-confirm-text">${text}</div><div style="display:flex; justify-content:center; gap:10px; margin-top:5px;"><div class="javdb-confirm-btn" id="confirm-cancel">取消</div><div class="javdb-confirm-btn danger" id="confirm-ok" style="background-color:${THEME_ORANGE}!important;border-color:${THEME_ORANGE}!important;color:#fff!important;">${btnText}</div></div>`; document.body.appendChild(modal); const close = () => { if(modal.parentNode) modal.parentNode.removeChild(modal); }; modal.querySelector('#confirm-cancel').onclick = close; modal.querySelector('#confirm-ok').onclick = () => { close(); onConfirm(); }; }
    function calculateAge(dobStr, isManual = false) { if (!dobStr) return "未知"; if (!isManual && dobStr.endsWith('-01-01')) return "未知"; let calcDateStr = dobStr; const parts = dobStr.split('-'); if (parts.length === 1) calcDateStr = `${dobStr}-01-01`; else if (parts.length === 2) calcDateStr = `${dobStr}-01`; const dob = new Date(calcDateStr); if (isNaN(dob.getTime())) return "未知"; const today = new Date(); let age = today.getFullYear() - dob.getFullYear(); const m = today.getMonth() - dob.getMonth(); if (m < 0 || (m === 0 && today.getDate() < dob.getDate())) age--; return age; }
