    function applyActorPageFilter() { const items = document.querySelectorAll('.movie-list .item'); if (!currentActorPageFilterName) { items.forEach(item => { item.classList.remove('javdb-hide-visited'); item.style.display = ''; }); if (enableFilterMode && isHiddenMode) applyFilter(); return; } const validIds = libraryCollections[currentActorPageFilterName] || []; items.forEach(item => { const titleStrong = item.querySelector('.video-title strong'); if (titleStrong) { const avId = titleStrong.textContent.trim(); if (validIds.includes(avId)) { item.classList.remove('javdb-hide-visited'); item.style.display = ''; } else { item.classList.add('javdb-hide-visited'); } } }); }
    function executeMerge(pageNames, targetName) { let lib = GM_getValue('libraryCollections', {}); let cache = GM_getValue('actorInfoCache', {}); let redirects = GM_getValue('actorRedirects', {}); let targetIds = lib[targetName] || []; let targetInfo = cache[targetName] || { dob: '', manual: false, url: window.location.href }; pageNames.forEach(name => { if (name !== targetName) { if (lib[name]) { targetIds = [...targetIds, ...lib[name]]; delete lib[name]; } if (cache[name]) { if (!targetInfo.dob && cache[name].dob) { targetInfo.dob = cache[name].dob; targetInfo.manual = cache[name].manual; } delete cache[name]; } redirects[name] = targetName; for (const key in redirects) { if (redirects[key] === name) { redirects[key] = targetName; } } } }); lib[targetName] = [...new Set(targetIds)]; targetInfo.url = window.location.href; cache[targetName] = targetInfo; GM_setValue('libraryCollections', lib); GM_setValue('actorInfoCache', cache); GM_setValue('actorRedirects', redirects); libraryCollections = lib; actorInfoCache = cache; actorRedirects = redirects; }

    function downloadImage(imageUrl, fileName, button = null, originalText = '') { return new Promise(resolve => { const isUserTriggered = !!button; if (isUserTriggered) { button.disabled = true; button.classList.add('downloading'); } GM_download({ url: imageUrl, name: fileName, onload: function() { if (isUserTriggered) { button.textContent = '已完成'; button.classList.remove('downloading'); setTimeout(() => { button.textContent = originalText; button.disabled = false; }, 2000); } resolve(true); }, onerror: function(error) { if (isUserTriggered) { button.textContent = '无图源'; button.classList.remove('downloading'); button.classList.add('download-failed'); setTimeout(() => { button.textContent = originalText; button.classList.remove('download-failed'); button.disabled = false; }, 3000); } resolve(false); } }); }); }
    async function getJavTrailersImageUrl(avId){try{const url=`https://www.dmm.co.jp/mono/dvd/-/search/=/searchstr=${encodeURIComponent(avId)}/`,res=await gmRequest(url,"GET",{"Cookie":"age_check_done=1;"}),match=res.responseText.match(/(?:https:)?\/\/pics\.dmm\.co\.jp\/[^"']+?ps\.jpg/i);if(match){let img=match[0];if(img.startsWith('//'))img='https:'+img;return img.replace('ps.jpg','pl.jpg');}}catch(e){}return null;}
