    async function handleMagnetButtonClick(event) { const button = event.target; button.dataset.originalText = 'Magnet'; button.dataset.originalColor = getComputedStyle(button).backgroundColor; const avId = getAvId(); const strictActors = getAllActorsFromPage(document, false); let namingActorName = ''; if (strictActors.length === 0 || strictActors.length > 4) { namingActorName = getActorNameFromTitleFallback(document); } else { namingActorName = strictActors.map(raw => getNamingActorName(raw)).join(' '); } if (!avId) return; await coreMagnetLogic(avId, namingActorName, button, null); }
    async function handleWaterfallMagnetClick(event) { const tag = event.target; if (!tag.classList.contains('tag') || (!tag.classList.contains('is-success') && !tag.classList.contains('is-warning'))) return; const text = tag.textContent.trim(); if (text !== '含磁鏈' && text !== '含中字磁鏈' && text !== '已下载' && text !== '已在库') return; if (text === '已在库') { const avIdNode = tag.closest('.item').querySelector('.video-title strong'), avId = avIdNode ? avIdNode.textContent.trim() : null; const data = playbackData[avId] || {}; if (data.embyId) handleEmbyPlay(avId, data.embyId); else alert("未找到 Emby ID，请执行同步补全数据。"); return; } if (!enableQuickDownload) return; tag.dataset.originalText = text; const item = tag.closest('.item'), boxLink = item.querySelector('.box'), avIdNode = item.querySelector('.video-title strong'), avId = avIdNode ? avIdNode.textContent.trim() : null; if (!avId) return; const detailUrl = boxLink.href; try { const response = await gmRequest(detailUrl); const doc = new DOMParser().parseFromString(response.responseText, "text/html"); const strictActors = getAllActorsFromPage(doc, false); let namingActorName = ''; if (strictActors.length === 0 || strictActors.length > 4) { namingActorName = getActorNameFromTitleFallback(doc); } else { namingActorName = strictActors.map(raw => getNamingActorName(raw)).join(' '); } await coreMagnetLogic(avId, namingActorName, tag, doc); } catch (e) { tag.textContent = '错误'; setTimeout(() => tag.textContent = text, 2000); } }
